INSERT INTO public.campaigns_catalog (id, name, description, objectives, topics, category, assets, availability, status, is_bespoke, reference_links, custom_events, tier, image_source, tiers, creatives, hidden)
VALUES ('455fd1b9-1af8-4670-8dc8-5eb2c3bd0bfe', 'Brand Plaques (Frame Headers)', 'In a busy practice, first impressions matter, and so does how your eyewear is displayed. If you''re investing in premium eyewear collections, you want to make sure your patients recognise their value from the moment they step through the door. That''s where brand plaques come in. 

